import { motion } from "framer-motion";
import { Trophy, TrendingUp, TrendingDown, Minus, Award, Users } from "lucide-react";
import { useAppStore } from "@/store/useAppStore";
import { translations, LanguageCode } from "@/data/translations";

// Re-export LeaderboardEntry type for backward compatibility
export interface LeaderboardEntry {
  rank: number;
  name: string;
  location: string;
  score: number;
  scans: number;
  change: "up" | "down" | "same";
  isCurrentUser?: boolean;
}

// eslint-disable-next-line @typescript-eslint/no-unused-vars
const Leaderboard = (_props?: { entries?: LeaderboardEntry[] }) => {
  const { leaderboard, selectedLanguage, user } = useAppStore();
  const t = translations[selectedLanguage as LanguageCode] || translations.en;

  // Filter to only show users (no fake data)
  const displayLeaderboard = leaderboard.filter(e => e.score >= 0 || e.scans >= 0);

  const getRankStyle = (rank: number) => {
    if (rank === 1) return { bg: "bg-gradient-to-r from-amber-400/20 to-yellow-400/20", border: "border-amber-400/30", text: "text-amber-400", medal: "≡ƒÑç" };
    if (rank === 2) return { bg: "bg-gradient-to-r from-slate-300/20 to-slate-400/20", border: "border-slate-400/30", text: "text-slate-300", medal: "≡ƒÑê" };
    if (rank === 3) return { bg: "bg-gradient-to-r from-amber-700/20 to-orange-700/20", border: "border-amber-700/30", text: "text-amber-600", medal: "≡ƒÑë" };
    return { bg: "bg-white/5", border: "border-white/10", text: "text-white/60", medal: null };
  };

  const getChangeIcon = (change: string) => {
    if (change === "up") return <TrendingUp className="w-3.5 h-3.5 text-emerald-400" />;
    if (change === "down") return <TrendingDown className="w-3.5 h-3.5 text-red-400" />;
    return <Minus className="w-3.5 h-3.5 text-white/30" />;
  };

  return (
    <div
      className="min-h-screen pb-24"
      style={{ background: "linear-gradient(160deg, #070d14 0%, #0d1a24 40%, #060b12 100%)" }}
    >
      <div className="p-4 space-y-4">
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          className="flex items-center justify-between pt-2"
        >
          <div>
            <div className="flex items-center gap-2 mb-1">
              <Trophy className="w-5 h-5 text-amber-400" />
              <h2 className="text-xl font-bold text-white">{t.leaderboardTitle || "Global League"}</h2>
            </div>
            <p className="text-sm text-white/40">
              {t.leaderboardSubtitle || "Based on scans & activity"}
            </p>
          </div>
          <div className="flex items-center gap-1.5 px-3 py-1.5 rounded-full bg-emerald-500/10 border border-emerald-500/20">
            <span className="w-2 h-2 rounded-full bg-emerald-400 animate-pulse" />
            <span className="text-emerald-400 text-xs font-semibold">Live</span>
          </div>
        </motion.div>

        {/* Scoring Guide */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.1 }}
          className="rounded-2xl border border-white/10 p-4"
          style={{ background: "rgba(255,255,255,0.04)" }}
        >
          <p className="text-xs text-white/50 font-medium mb-2 uppercase tracking-wider">How Points Work</p>
          <div className="grid grid-cols-3 gap-3 text-center">
            <div className="p-2 rounded-xl bg-emerald-500/10 border border-emerald-500/20">
              <div className="text-lg font-bold text-emerald-400">+100</div>
              <div className="text-[10px] text-white/40">per scan</div>
            </div>
            <div className="p-2 rounded-xl bg-blue-500/10 border border-blue-500/20">
              <div className="text-lg font-bold text-blue-400">+50</div>
              <div className="text-[10px] text-white/40">{t.productListed}</div>
            </div>
            <div className="p-2 rounded-xl bg-amber-500/10 border border-amber-500/20">
              <div className="text-lg font-bold text-amber-400">+200</div>
              <div className="text-[10px] text-white/40">land analysis</div>
            </div>
          </div>
        </motion.div>

        {/* Leaderboard List */}
        {displayLeaderboard.length === 0 ? (
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className="rounded-2xl border border-white/10 p-10 text-center"
            style={{ background: "rgba(255,255,255,0.04)" }}
          >
            <Users className="w-12 h-12 text-white/20 mx-auto mb-4" />
            <h3 className="text-white font-bold text-lg mb-2">Be the First on the Board!</h3>
            <p className="text-white/40 text-sm max-w-xs mx-auto">
              {user
                ? "Scan crops to earn points and claim your spot on the leaderboard!"
                : "Login and scan crops to join the global farmer rankings."}
            </p>
            {!user && (
              <div className="mt-4 px-4 py-2 bg-emerald-600/20 border border-emerald-500/30 rounded-xl inline-block text-emerald-400 text-sm font-semibold">
                Login to Compete
              </div>
            )}
          </motion.div>
        ) : (
          <motion.div
            className="space-y-2"
            initial="hidden"
            animate="show"
            variants={{
              hidden: { opacity: 0 },
              show: { opacity: 1, transition: { staggerChildren: 0.06 } }
            }}
          >
            {displayLeaderboard.map((entry, index) => {
              const style = getRankStyle(entry.rank);
              return (
                <motion.div
                  key={`${entry.name}-${index}`}
                  variants={{
                    hidden: { opacity: 0, x: -12 },
                    show: { opacity: 1, x: 0 }
                  }}
                  className={`relative rounded-2xl border p-4 flex items-center gap-3 ${style.bg} ${style.border} ${entry.isCurrentUser ? "ring-1 ring-emerald-500/40" : ""}`}
                >
                  {/* Rank */}
                  <div className={`w-9 h-9 rounded-xl flex items-center justify-center text-sm font-black ${style.text} border ${style.border} flex-shrink-0 ${style.bg}`}>
                    {style.medal || `#${entry.rank}`}
                  </div>

                  {/* Avatar Initial */}
                  <div className={`w-10 h-10 rounded-full flex items-center justify-center text-sm font-bold text-white flex-shrink-0 ${entry.isCurrentUser ? "bg-emerald-600" : "bg-white/10"}`}>
                    {entry.name.charAt(0).toUpperCase()}
                  </div>

                  {/* Info */}
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-1.5">
                      <h4 className="font-bold text-white text-sm truncate">{entry.name}</h4>
                      {entry.isCurrentUser && (
                        <span className="text-[9px] bg-emerald-500/20 text-emerald-400 px-1.5 py-0.5 rounded-full font-bold border border-emerald-500/30 flex-shrink-0">
                          {t.rankYou || "You"}
                        </span>
                      )}
                    </div>
                    <p className="text-xs text-white/40 truncate">{entry.location}</p>
                  </div>

                  {/* Score & Scans */}
                  <div className="text-right flex-shrink-0">
                    <div className="text-sm font-black text-white">{entry.score.toLocaleString()}</div>
                    <div className="text-[10px] text-white/30">{entry.scans} scans</div>
                  </div>

                  {/* Change */}
                  <div className="flex-shrink-0 ml-1">
                    {getChangeIcon(entry.change)}
                  </div>
                </motion.div>
              );
            })}
          </motion.div>
        )}

        {/* Motivational Footer */}
        {displayLeaderboard.length > 0 && user && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.4 }}
            className="rounded-2xl border border-white/10 p-4 text-center"
            style={{ background: "rgba(255,255,255,0.03)" }}
          >
            <Award className="w-6 h-6 text-amber-400 mx-auto mb-2" />
            <p className="text-white/60 text-xs">Scan more crops to earn points and climb the ranks!</p>
            <p className="text-white/30 text-[10px] mt-1">{t.rankingsUpdateRealtime}</p>
          </motion.div>
        )}
      </div>
    </div>
  );
};

export { Leaderboard };
export default Leaderboard;

import { useState, useEffect } from "react";
import { motion } from "framer-motion";
import { Play, ExternalLink, Film, Search, Youtube } from "lucide-react";
import { searchYouTubeVideo } from "@/services/youtube";
import { cn } from "@/lib/utils";

interface VideoPlayerProps {
    initialVideoUrl?: string;
    cropName?: string;
    diseaseName: string;
    className?: string;
}

// Extract video ID from any YouTube URL format
const extractVideoId = (url: string): string | null => {
    if (!url) return null;
    // Already an embed URL: https://www.youtube.com/embed/VIDEO_ID
    const embedMatch = url.match(/embed\/([a-zA-Z0-9_-]{11})/);
    if (embedMatch) return embedMatch[1];
    // Watch URL: https://www.youtube.com/watch?v=VIDEO_ID
    const watchMatch = url.match(/[?&]v=([a-zA-Z0-9_-]{11})/);
    if (watchMatch) return watchMatch[1];
    // Short URL: https://youtu.be/VIDEO_ID
    const shortMatch = url.match(/youtu\.be\/([a-zA-Z0-9_-]{11})/);
    if (shortMatch) return shortMatch[1];
    return null;
};

const buildEmbedUrl = (videoId: string) =>
    `https://www.youtube.com/embed/${videoId}?rel=0&modestbranding=1&playsinline=1&autoplay=1`;

const buildThumbnailUrl = (videoId: string) =>
    `https://img.youtube.com/vi/${videoId}/maxresdefault.jpg`;

const buildWatchUrl = (videoId: string) =>
    `https://www.youtube.com/watch?v=${videoId}`;

export const VideoPlayer = ({
    initialVideoUrl,
    cropName,
    diseaseName,
    className,
}: VideoPlayerProps) => {
    const [videoId, setVideoId] = useState<string | null>(
        initialVideoUrl ? extractVideoId(initialVideoUrl) : null
    );
    const [isLoading, setIsLoading] = useState(!initialVideoUrl);
    const [isPlaying, setIsPlaying] = useState(false); // user clicked play
    const [thumbnailFailed, setThumbnailFailed] = useState(false);
    const [showEmbed, setShowEmbed] = useState(false); // NEW: toggle between thumbnail and iframe

    const searchQuery = `${cropName || ""} ${diseaseName} treatment guide`.trim();

    // When the prop changes (new scan result), reset and update
    useEffect(() => {
        const newId = initialVideoUrl ? extractVideoId(initialVideoUrl) : null;
        if (newId && newId !== videoId) {
            console.log(`[VideoPlayer] Setting video ID: ${newId} from URL: ${initialVideoUrl}`);
            setVideoId(newId);
            setIsPlaying(false);
            setIsLoading(false);
            setThumbnailFailed(false);
            setShowEmbed(false);
        }
    }, [initialVideoUrl]);

    // If no initial URL, search via YouTube API service
    useEffect(() => {
        if (!initialVideoUrl && !videoId) {
            console.log(`[VideoPlayer] No initial URL, searching for: "${searchQuery}"`);
            setIsLoading(true);
            searchYouTubeVideo(searchQuery).then((url) => {
                const id = extractVideoId(url);
                console.log(`[VideoPlayer] Search result - URL: ${url}, ID: ${id}`);
                setVideoId(id);
                setIsLoading(false);
            }).catch((err) => {
                console.error('[VideoPlayer] Search failed:', err);
                setIsLoading(false);
            });
        }
    }, []);

    return (
        <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className={cn(
                "rounded-xl overflow-hidden border border-white/10 shadow-lg bg-black/40 backdrop-blur-md",
                className
            )}
        >
            {/* Header */}
            <div className="bg-white/5 px-4 py-3 border-b border-white/10 flex justify-between items-center">
                <h4 className="text-[10px] font-black text-white/90 flex items-center gap-2 uppercase tracking-tighter">
                    <Film className="w-3.5 h-3.5 text-emerald-400" />
                    <span>How to Cure: {diseaseName}</span>
                </h4>
                {videoId && (
                    <a
                        href={buildWatchUrl(videoId)}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="text-[10px] text-emerald-400 font-bold uppercase hover:text-emerald-300 transition-colors bg-emerald-500/10 px-2 py-0.5 rounded-full border border-emerald-500/20"
                    >
                        Watch <ExternalLink className="w-2.5 h-2.5 ml-1 inline" />
                    </a>
                )}
            </div>

            {/* Video Container */}
            <div className="relative aspect-video bg-black w-full overflow-hidden">

                {/* ΓöÇΓöÇ Loading State ΓöÇΓöÇ */}
                {isLoading && (
                    <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/90 z-20">
                        <div className="w-8 h-8 border-2 border-emerald-500 border-t-transparent rounded-full animate-spin mb-3" />
                        <p className="text-[10px] font-bold text-emerald-500/60 uppercase tracking-widest">
                            Finding Best Video...
                        </p>
                    </div>
                )}

                {/* ΓöÇΓöÇ Thumbnail with Watch Button (Better UX - always works) ΓöÇΓöÇ */}  
                {!isLoading && videoId && (
                    <div className="absolute inset-0 w-full h-full flex items-center justify-center group">
                        {/* Thumbnail background */}
                        {!thumbnailFailed ? (
                            <img
                                src={buildThumbnailUrl(videoId)}
                                alt="Video thumbnail"
                                className="absolute inset-0 w-full h-full object-cover"
                                onError={() => setThumbnailFailed(true)}
                            />
                        ) : (
                            <div className="absolute inset-0 bg-gradient-to-br from-emerald-900/60 via-emerald-950/80 to-black" />
                        )}
                        
                        {/* Dark overlay */}
                        <div className="absolute inset-0 bg-black/40" />
                        
                        {/* Content */}
                        <div className="relative z-10 flex flex-col items-center justify-center p-6 text-center">
                            {/* YouTube Icon */}
                            <motion.div
                                initial={{ scale: 0.9, opacity: 0 }}
                                animate={{ scale: 1, opacity: 1 }}
                                className="mb-4"
                            >
                                <div className="w-20 h-20 rounded-full bg-red-600 flex items-center justify-center shadow-2xl">
                                    <Youtube className="w-11 h-11 text-white" fill="currentColor" />
                                </div>
                            </motion.div>
                            
                            {/* Title */}
                            <h3 className="text-white font-bold text-lg mb-2">
                                How to Cure {diseaseName}
                            </h3>
                            <p className="text-white/70 text-sm mb-6 max-w-xs">
                                Learn treatment methods and disease control techniques
                            </p>
                            
                            {/* Watch Button */}
                            <motion.a
                                href={`https://www.youtube.com/results?search_query=${encodeURIComponent(`${cropName || ''} ${diseaseName} how to cure treatment control`)}`}
                                target="_blank"
                                rel="noopener noreferrer"
                                whileHover={{ scale: 1.05 }}
                                whileTap={{ scale: 0.95 }}
                                className="inline-flex items-center gap-2 px-6 py-3 bg-red-600 hover:bg-red-700 text-white font-bold rounded-full shadow-lg transition-all"
                            >
                                <Play className="w-5 h-5" fill="currentColor" />
                                Search YouTube for Cure
                                <ExternalLink className="w-4 h-4" />
                            </motion.a>
                            
                            {/* Alternative search link */}
                            <a
                                href={`https://www.youtube.com/results?search_query=${encodeURIComponent(searchQuery)}`}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="mt-4 text-xs text-white/50 hover:text-white/80 transition-colors flex items-center gap-1"
                            >
                                <Search className="w-3 h-3" />
                                Search for more videos
                            </a>
                        </div>
                    </div>
                )}

                {/* ΓöÇΓöÇ No Video State ΓöÇΓöÇ */}
                {!isLoading && !videoId && (
                    <div className="absolute inset-0 flex flex-col items-center justify-center p-6 text-center bg-gradient-to-br from-emerald-900/40 via-zinc-950/80 to-black">
                        <div className="w-16 h-16 rounded-full bg-red-600/20 flex items-center justify-center mb-4 border-2 border-red-600/30">
                            <Youtube className="w-8 h-8 text-red-500" />
                        </div>
                        <h5 className="text-white font-bold text-sm mb-2">Treatment Video Guide</h5>
                        <p className="text-xs text-white/60 mb-6 max-w-[220px] mx-auto leading-relaxed">
                            Watch detailed treatment instructions on YouTube
                        </p>
                        <a
                            href={`https://www.youtube.com/results?search_query=${encodeURIComponent(searchQuery)}`}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="inline-flex items-center gap-2 px-5 py-2.5 bg-red-600 hover:bg-red-700 text-white rounded-full text-sm font-bold uppercase transition-all shadow-lg"
                        >
                            <Search className="w-4 h-4" />
                            Search YouTube
                        </a>
                    </div>
                )}
            </div>

            {/* Footer */}
            <div className="bg-black/80 px-4 py-2.5 flex justify-between items-center border-t border-white/5">
                <div className="flex items-center gap-2">
                    <Youtube className="w-3.5 h-3.5 text-red-500" />
                    <p className="text-[9px] text-white/40 uppercase font-bold tracking-wider">
                        Video Guide Available
                    </p>
                </div>
                {videoId && (
                    <a
                        href={buildWatchUrl(videoId)}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="text-[9px] font-black text-red-500 uppercase tracking-tighter hover:text-red-400 transition-colors flex items-center gap-1"
                    >
                        Open on YouTube <ExternalLink className="w-3 h-3" />
                    </a>
                )}
            </div>
        </motion.div>
    );
};

import * as React from "react";
import * as NavigationMenuPrimitive from "@radix-ui/react-navigation-menu";
import { cva } from "class-variance-authority";
import { ChevronDown } from "lucide-react";

import { cn } from "@/lib/utils";

const NavigationMenu = React.forwardRef<
  React.ElementRef<typeof NavigationMenuPrimitive.Root>,
  React.ComponentPropsWithoutRef<typeof NavigationMenuPrimitive.Root>
>(({ className, children, ...props }, ref) => (
  <NavigationMenuPrimitive.Root
    ref={ref}
    className={cn("relative z-10 flex max-w-max flex-1 items-center justify-center", className)}
    {...props}
  >
    {children}
    <NavigationMenuViewport />
  </NavigationMenuPrimitive.Root>
));
NavigationMenu.displayName = NavigationMenuPrimitive.Root.displayName;

const NavigationMenuList = React.forwardRef<
  React.ElementRef<typeof NavigationMenuPrimitive.List>,
  React.ComponentPropsWithoutRef<typeof NavigationMenuPrimitive.List>
>(({ className, ...props }, ref) => (
  <NavigationMenuPrimitive.List
    ref={ref}
    className={cn("group flex flex-1 list-none items-center justify-center space-x-1", className)}
    {...props}
  />
));
NavigationMenuList.displayName = NavigationMenuPrimitive.List.displayName;

const NavigationMenuItem = NavigationMenuPrimitive.Item;

const navigationMenuTriggerStyle = cva(
  "group inline-flex h-10 w-max items-center justify-center rounded-md bg-background px-4 py-2 text-sm font-medium transition-colors hover:bg-accent hover:text-accent-foreground focus:bg-accent focus:text-accent-foreground focus:outline-none disabled:pointer-events-none disabled:opacity-50 data-[active]:bg-accent/50 data-[state=open]:bg-accent/50",
);

const NavigationMenuTrigger = React.forwardRef<
  React.ElementRef<typeof NavigationMenuPrimitive.Trigger>,
  React.ComponentPropsWithoutRef<typeof NavigationMenuPrimitive.Trigger>
>(({ className, children, ...props }, ref) => (
  <NavigationMenuPrimitive.Trigger
    ref={ref}
    className={cn(navigationMenuTriggerStyle(), "group", className)}
    {...props}
  >
    {children}{" "}
    <ChevronDown
      className="relative top-[1px] ml-1 h-3 w-3 transition duration-200 group-data-[state=open]:rotate-180"
      aria-hidden="true"
    />
  </NavigationMenuPrimitive.Trigger>
));
NavigationMenuTrigger.displayName = NavigationMenuPrimitive.Trigger.displayName;

const NavigationMenuContent = React.forwardRef<
  React.ElementRef<typeof NavigationMenuPrimitive.Content>,
  React.ComponentPropsWithoutRef<typeof NavigationMenuPrimitive.Content>
>(({ className, ...props }, ref) => (
  <NavigationMenuPrimitive.Content
    ref={ref}
    className={cn(
      "left-0 top-0 w-full data-[motion^=from-]:animate-in data-[motion^=to-]:animate-out data-[motion^=from-]:fade-in data-[motion^=to-]:fade-out data-[motion=from-end]:slide-in-from-right-52 data-[motion=from-start]:slide-in-from-left-52 data-[motion=to-end]:slide-out-to-right-52 data-[motion=to-start]:slide-out-to-left-52 md:absolute md:w-auto",
      className,
    )}
    {...props}
  />
));
NavigationMenuContent.displayName = NavigationMenuPrimitive.Content.displayName;

const NavigationMenuLink = NavigationMenuPrimitive.Link;

const NavigationMenuViewport = React.forwardRef<
  React.ElementRef<typeof NavigationMenuPrimitive.Viewport>,
  React.ComponentPropsWithoutRef<typeof NavigationMenuPrimitive.Viewport>
>(({ className, ...props }, ref) => (
  <div className={cn("absolute left-0 top-full flex justify-center")}>
    <NavigationMenuPrimitive.Viewport
      className={cn(
        "origin-top-center relative mt-1.5 h-[var(--radix-navigation-menu-viewport-height)] w-full overflow-hidden rounded-md border bg-popover text-popover-foreground shadow-lg data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-90 md:w-[var(--radix-navigation-menu-viewport-width)]",
        className,
      )}
      ref={ref}
      {...props}
    />
  </div>
));
NavigationMenuViewport.displayName = NavigationMenuPrimitive.Viewport.displayName;

const NavigationMenuIndicator = React.forwardRef<
  React.ElementRef<typeof NavigationMenuPrimitive.Indicator>,
  React.ComponentPropsWithoutRef<typeof NavigationMenuPrimitive.Indicator>
>(({ className, ...props }, ref) => (
  <NavigationMenuPrimitive.Indicator
    ref={ref}
    className={cn(
      "top-full z-[1] flex h-1.5 items-end justify-center overflow-hidden data-[state=visible]:animate-in data-[state=hidden]:animate-out data-[state=hidden]:fade-out data-[state=visible]:fade-in",
      className,
    )}
    {...props}
  >
    <div className="relative top-[60%] h-2 w-2 rotate-45 rounded-tl-sm bg-border shadow-md" />
  </NavigationMenuPrimitive.Indicator>
));
NavigationMenuIndicator.displayName = NavigationMenuPrimitive.Indicator.displayName;

export {
  navigationMenuTriggerStyle,
  NavigationMenu,
  NavigationMenuList,
  NavigationMenuItem,
  NavigationMenuContent,
  NavigationMenuTrigger,
  NavigationMenuLink,
  NavigationMenuIndicator,
  NavigationMenuViewport,
};

import * as React from "react";
import { Slot } from "@radix-ui/react-slot";
import { VariantProps, cva } from "class-variance-authority";
import { PanelLeft } from "lucide-react";

import { useIsMobile } from "@/hooks/use-mobile";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Separator } from "@/components/ui/separator";
import { Sheet, SheetContent } from "@/components/ui/sheet";
import { Skeleton } from "@/components/ui/skeleton";
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";

const SIDEBAR_COOKIE_NAME = "sidebar:state";
const SIDEBAR_COOKIE_MAX_AGE = 60 * 60 * 24 * 7;
const SIDEBAR_WIDTH = "16rem";
const SIDEBAR_WIDTH_MOBILE = "18rem";
const SIDEBAR_WIDTH_ICON = "3rem";
const SIDEBAR_KEYBOARD_SHORTCUT = "b";

type SidebarContext = {
  state: "expanded" | "collapsed";
  open: boolean;
  setOpen: (open: boolean) => void;
  openMobile: boolean;
  setOpenMobile: (open: boolean) => void;
  isMobile: boolean;
  toggleSidebar: () => void;
};

const SidebarContext = React.createContext<SidebarContext | null>(null);

function useSidebar() {
  const context = React.useContext(SidebarContext);
  if (!context) {
    throw new Error("useSidebar must be used within a SidebarProvider.");
  }

  return context;
}

const SidebarProvider = React.forwardRef<
  HTMLDivElement,
  React.ComponentProps<"div"> & {
    defaultOpen?: boolean;
    open?: boolean;
    onOpenChange?: (open: boolean) => void;
  }
>(({ defaultOpen = true, open: openProp, onOpenChange: setOpenProp, className, style, children, ...props }, ref) => {
  const isMobile = useIsMobile();
  const [openMobile, setOpenMobile] = React.useState(false);

  // This is the internal state of the sidebar.
  // We use openProp and setOpenProp for control from outside the component.
  const [_open, _setOpen] = React.useState(defaultOpen);
  const open = openProp ?? _open;
  const setOpen = React.useCallback(
    (value: boolean | ((value: boolean) => boolean)) => {
      const openState = typeof value === "function" ? value(open) : value;
      if (setOpenProp) {
        setOpenProp(openState);
      } else {
        _setOpen(openState);
      }

      // This sets the cookie to keep the sidebar state.
      document.cookie = `${SIDEBAR_COOKIE_NAME}=${openState}; path=/; max-age=${SIDEBAR_COOKIE_MAX_AGE}`;
    },
    [setOpenProp, open],
  );

  // Helper to toggle the sidebar.
  const toggleSidebar = React.useCallback(() => {
    return isMobile ? setOpenMobile((open) => !open) : setOpen((open) => !open);
  }, [isMobile, setOpen, setOpenMobile]);

  // Adds a keyboard shortcut to toggle the sidebar.
  React.useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === SIDEBAR_KEYBOARD_SHORTCUT && (event.metaKey || event.ctrlKey)) {
        event.preventDefault();
        toggleSidebar();
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [toggleSidebar]);

  // We add a state so that we can do data-state="expanded" or "collapsed".
  // This makes it easier to style the sidebar with Tailwind classes.
  const state = open ? "expanded" : "collapsed";

  const contextValue = React.useMemo<SidebarContext>(
    () => ({
      state,
      open,
      setOpen,
      isMobile,
      openMobile,
      setOpenMobile,
      toggleSidebar,
    }),
    [state, open, setOpen, isMobile, openMobile, setOpenMobile, toggleSidebar],
  );

  return (
    <SidebarContext.Provider value={contextValue}>
      <TooltipProvider delayDuration={0}>
        <div
          style={
            {
              "--sidebar-width": SIDEBAR_WIDTH,
              "--sidebar-width-icon": SIDEBAR_WIDTH_ICON,
              ...style,
            } as React.CSSProperties
          }
          className={cn("group/sidebar-wrapper flex min-h-svh w-full has-[[data-variant=inset]]:bg-sidebar", className)}
          ref={ref}
          {...props}
        >
          {children}
        </div>
      </TooltipProvider>
    </SidebarContext.Provider>
  );
});
SidebarProvider.displayName = "SidebarProvider";

const Sidebar = React.forwardRef<
  HTMLDivElement,
  React.ComponentProps<"div"> & {
    side?: "left" | "right";
    variant?: "sidebar" | "floating" | "inset";
    collapsible?: "offcanvas" | "icon" | "none";
  }
>(({ side = "left", variant = "sidebar", collapsible = "offcanvas", className, children, ...props }, ref) => {
  const { isMobile, state, openMobile, setOpenMobile } = useSidebar();

  if (collapsible === "none") {
    return (
      <div
        className={cn("flex h-full w-[--sidebar-width] flex-col bg-sidebar text-sidebar-foreground", className)}
        ref={ref}
        {...props}
      >
        {children}
      </div>
    );
  }

  if (isMobile) {
    return (
      <Sheet open={openMobile} onOpenChange={setOpenMobile} {...props}>
        <SheetContent
          data-sidebar="sidebar"
          data-mobile="true"
          className="w-[--sidebar-width] bg-sidebar p-0 text-sidebar-foreground [&>button]:hidden"
          style={
            {
              "--sidebar-width": SIDEBAR_WIDTH_MOBILE,
            } as React.CSSProperties
          }
          side={side}
        >
          <div className="flex h-full w-full flex-col">{children}</div>
        </SheetContent>
      </Sheet>
    );
  }

  return (
    <div
      ref={ref}
      className="group peer hidden text-sidebar-foreground md:block"
      data-state={state}
      data-collapsible={state === "collapsed" ? collapsible : ""}
      data-variant={variant}
      data-side={side}
    >
      {/* This is what handles the sidebar gap on desktop */}
      <div
        className={cn(
          "relative h-svh w-[--sidebar-width] bg-transparent transition-[width] duration-200 ease-linear",
          "group-data-[collapsible=offcanvas]:w-0",
          "group-data-[side=right]:rotate-180",
          variant === "floating" || variant === "inset"
            ? "group-data-[collapsible=icon]:w-[calc(var(--sidebar-width-icon)_+_theme(spacing.4))]"
            : "group-data-[collapsible=icon]:w-[--sidebar-width-icon]",
        )}
      />
      <div
        className={cn(
          "fixed inset-y-0 z-10 hidden h-svh w-[--sidebar-width] transition-[left,right,width] duration-200 ease-linear md:flex",
          side === "left"
            ? "left-0 group-data-[collapsible=offcanvas]:left-[calc(var(--sidebar-width)*-1)]"
            : "right-0 group-data-[collapsible=offcanvas]:right-[calc(var(--sidebar-width)*-1)]",
          // Adjust the padding for floating and inset variants.
          variant === "floating" || variant === "inset"
            ? "p-2 group-data-[collapsible=icon]:w-[calc(var(--sidebar-width-icon)_+_theme(spacing.4)_+2px)]"
            : "group-data-[collapsible=icon]:w-[--sidebar-width-icon] group-data-[side=left]:border-r group-data-[side=right]:border-l",
          className,
        )}
        {...props}
      >
        <div
          data-sidebar="sidebar"
          className="flex h-full w-full flex-col bg-sidebar group-data-[variant=floating]:rounded-lg group-data-[variant=floating]:border group-data-[variant=floating]:border-sidebar-border group-data-[variant=floating]:shadow"
        >
          {children}
        </div>
      </div>
    </div>
  );
});
Sidebar.displayName = "Sidebar";

