                        </div>
                        <p className="text-3xl font-bold text-white">{totalScans}</p>
                        <p className="text-xs text-white/40 mt-1">{timeRange === 'week' ? t.thisWeek : timeRange === 'month' ? t.thisMonth : t.thisYear}</p>
