                                    />
                                    <Legend iconType="circle" wrapperStyle={{ color: 'rgba(255,255,255,0.6)', fontSize: 11 }} />
                                    <Bar dataKey="revenue" name={t.support} fill="#10b981" radius={[4, 4, 0, 0]} barSize={16} />
